external_knowledge:
- 'contests' can refer to 'elections';
- 'ballots cast' can mean 'total votes cast';
- 'voter participation rates' can be interpreted as 'voter turnout percentage';
- 'victorious contender' refers to 'winner candidate';
- 'kind of ballot system' can mean 'voting system type'.

sql:
SELECT region_name, region_type 
FROM geographic_regions
WHERE region_type = 'county';

external_knowledge:
- 'leading contenders' refers to the candidates with the highest number of votes;
- 'tally of ballots' refers to the total votes each candidate received;
- 'presidential contest from 2020' refers to the '2020 United States Presidential Election'.

sql:
SELECT region_id, population, age, income, race, ethnicity, gender_distribution, education_level
FROM demographics
WHERE income > 50000;
